import{_ as a,o as t,c as o,a1 as n}from"./chunks/framework.BwhMLafE.js";const h=JSON.parse('{"title":"Grammar Writing Guidelines","description":"","frontmatter":{},"headers":[],"relativePath":"grammar_guidelines.md","filePath":"grammar_guidelines.md"}'),i={name:"grammar_guidelines.md"};function s(r,e,l,c,d,p){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="grammar-writing-guidelines" tabindex="-1">Grammar Writing Guidelines <a class="header-anchor" href="#grammar-writing-guidelines" aria-label="Permalink to &quot;Grammar Writing Guidelines&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#1-file-structure--rule-syntax-grm-files">1. File Structure &amp; Rule Syntax (<code>.grm</code> files)</a></li><li><a href="#2-variable-naming--ast-generation">2. Variable Naming &amp; AST Generation</a></li><li><a href="#3-terminal-symbols">3. Terminal Symbols</a></li><li><a href="#4-procedure-hooks-procedure_name">4. Procedure Hooks (<code>@procedure_name</code>)</a></li></ul><hr><p>This guide details the syntax, conventions, and compile-time annotations supported by this repository&#39;s parser generators (LL and LR).</p><hr><h2 id="_1-file-structure-rule-syntax-grm-files" tabindex="-1">1. File Structure &amp; Rule Syntax (<code>.grm</code> files) <a class="header-anchor" href="#_1-file-structure-rule-syntax-grm-files" aria-label="Permalink to &quot;1. File Structure &amp; Rule Syntax (\`.grm\` files)&quot;">​</a></h2><ul><li><p><strong>Rule Structure:</strong> Each grammar rule is defined by the LHS (Left-Hand Side) variable symbol on a single line, followed by its alternative productions.</p></li><li><p><strong>Alternation:</strong> Each alternative production must start with a pipe character <code>|</code> on a new line, followed by space-separated symbols:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Value</span></span>
<span class="line"><span>| &quot;{&quot; OptionalBlank ObjectMembers OptionalBlank</span></span>
<span class="line"><span>| &quot;null&quot; OptionalBlank</span></span></code></pre></div></li><li><p><strong>Epsilon (Empty Productions):</strong> An empty production is represented by a single pipe <code>|</code> with no trailing symbols:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>OptionalBlank</span></span>
<span class="line"><span>| space _OptionalBlankTail</span></span>
<span class="line"><span>|</span></span></code></pre></div></li><li><p><strong>Formatting:</strong> Rules must be separated by at least one blank line. The first variable defined in the file is automatically treated as the parser&#39;s entry point.</p></li></ul><hr><h2 id="_2-variable-naming-ast-generation" tabindex="-1">2. Variable Naming &amp; AST Generation <a class="header-anchor" href="#_2-variable-naming-ast-generation" aria-label="Permalink to &quot;2. Variable Naming &amp; AST Generation&quot;">​</a></h2><p>The parser generator statically configures the Abstract Syntax Tree (AST) node creation based on the naming style of the variable symbols:</p><ul><li><strong>PascalCase Validation:</strong> All variable names must be written in PascalCase. The generator validates this at compile-time.</li><li><strong>AST-Enabled Variables:</strong> Variables starting with a Capital letter (e.g. <code>Value</code>, <code>ObjectMembers</code>) allocate an AST node when matched.</li><li><strong>Non-AST Helper Variables:</strong> Variables starting with an underscore (e.g. <code>_StringContent</code>, <code>_OptionalBlank</code>) are helper rules. The generator completely skips allocating AST nodes for them, optimizing runtime parsing performance and memory footprint.</li></ul><hr><h2 id="_3-terminal-symbols" tabindex="-1">3. Terminal Symbols <a class="header-anchor" href="#_3-terminal-symbols" aria-label="Permalink to &quot;3. Terminal Symbols&quot;">​</a></h2><p>Terminals in rules represent either exact character literals or pre-defined generative character classes:</p><ul><li><strong>Normal Terminals:</strong> Exact character/string matches can be written in one of two quoting styles: <ul><li><strong>Double-quoted:</strong> Wrapped in double quotes (e.g., <code>&quot;{&quot;</code>, <code>&quot;null&quot;</code>, <code>&quot;+&quot;</code>).</li><li><strong>Single-quoted:</strong> Wrapped in single quotes at the start and terminating with the <code>\\x03</code> (0x03) byte (e.g., <code>&#39;&quot;\\x03</code> representing the <code>&quot;</code> character).</li></ul></li><li><strong>Generative Character Terminals:</strong> Unquoted keyword names map to specific sets of ASCII characters: <ul><li><code>digit</code>: Matches <code>&#39;0&#39;-&#39;9&#39;</code></li><li><code>letter</code>: Matches <code>&#39;a&#39;-&#39;z&#39;</code> and <code>&#39;A&#39;-&#39;Z&#39;</code></li><li><code>lowercase_letter</code>: Matches <code>&#39;a&#39;-&#39;z&#39;</code></li><li><code>uppercase_letter</code>: Matches <code>&#39;A&#39;-&#39;Z&#39;</code></li><li><code>whitespace</code>: Matches whitespace characters (<code>\\t</code>, <code>\\n</code>, <code>\\r</code>, <code>\\x0b</code>, <code>\\x0c</code>, <code></code>)</li><li><code>punctuation</code>: Matches standard punctuation characters</li><li><code>character</code>: Matches letters, digits, punctuation, and whitespace</li><li><code>operator</code>: Matches operator symbols (<code>+</code>, <code>*</code>, <code>/</code>, <code>&amp;</code>, <code>|</code>, <code>&gt;</code>, <code>&gt;=</code>, <code>&lt;</code>, <code>&lt;=</code>, <code>=</code>)</li><li><code>new_line</code>: Matches <code>\\n</code></li><li><code>space</code>: Matches space <code>&#39; &#39;</code></li><li><code>block_start</code>: Matches control character <code>\\x01</code> (representing the start of a block when indentation syntax is enabled for the parser, see <a href="./procedures.html#indentation-syntax">Reduction Procedures</a> for details)</li><li><code>block_end</code>: Matches control character <code>\\x02</code> (representing the end of a block when indentation syntax is enabled for the parser, see <a href="./procedures.html#indentation-syntax">Reduction Procedures</a> for details)</li></ul></li><li><strong>Generative Suffix Exceptions:</strong> Any generative terminal can have exceptions appended as a suffix chain introduced by the <code>^</code> character followed by a normal terminal (e.g., <code>character^&quot;\\n&quot;</code>, <code>character^&#39;&quot;\\x03</code>, or multiple chained exceptions like <code>digit^&quot;1&quot;^&quot;3&quot;</code>). The exception terminal&#39;s characters are excluded from the allowed terminal characters of the generative class.</li></ul><hr><h2 id="_4-procedure-hooks-procedure-name" tabindex="-1">4. Procedure Hooks (<code>@procedure_name</code>) <a class="header-anchor" href="#_4-procedure-hooks-procedure-name" aria-label="Permalink to &quot;4. Procedure Hooks (\`@procedure_name\`)&quot;">​</a></h2><p>You can register custom semantic logic to run automatically during parsing by appending a procedure name with <code>@</code>. There are four kinds of explicit grammar hooks:</p><ol><li><p><strong>LHS Variable Hook:</strong> Attaches to the left-hand-side variable definition, executing whenever this variable is reduced anywhere:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Value@drop_children</span></span>
<span class="line"><span>| Object OptionalBlank</span></span>
<span class="line"><span>| Array OptionalBlank</span></span></code></pre></div></li><li><p><strong>RHS Symbol Hook:</strong> Attaches to a right-hand-side symbol (either a variable, or a terminal symbol if <code>--ast-for-terminals</code> is active), executing only when matched in that position:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ArrayMembers</span></span>
<span class="line"><span>| Value ArrayMembersTail@replace_with_children &quot;]&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Number</span></span>
<span class="line"><span>| digit@my_digit_hook _PositiveIntegerNumberTail</span></span></code></pre></div></li><li><p><strong>Production Hook:</strong> Attaches to a complete right-hand-side production, placed immediately after the pipe (<code>|</code>), executing when the production is reduced:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FloatTail@drop_self</span></span>
<span class="line"><span>|@drop_self &quot;.&quot; PositiveIntegerNumber</span></span>
<span class="line"><span>|</span></span></code></pre></div></li></ol><hr><p>For detailed information on implicit hooks (<code>reduction</code>, <code>reduction_&lt;SymbolName&gt;</code>), compiler AST requirements, and how to write hook functions in Zig, see the <a href="./procedures.html">Reduction Procedures User Guide</a>.</p>`,22)])])}const m=a(i,[["render",s]]);export{h as __pageData,m as default};
